4862	    return op->emitOpError() << "expect at least 1 operand";
4863	
4864	  if (numOperands != numResults)
4865	    return op->emitOpError() << "expect same number of operands and results";
4866	
4867	  // Verify identities if provided:
4868	  // a) #_identities == #_operands
4869	  // b) type(identities[i]) == type(operands[i]) 0 <= i < operands.size
4870	  if (identities) {
4871	    size_t numIdentities = identities.size();
4872	    if (numOperands != numIdentities)
4873	      return op->emitOpError()
4874	             << "expect identities to match the number of operands but got: "
4875	             << numOperands << " operands and " << numIdentities
4876	             << " identities";
4877	
4878	    for (size_t idx = 0; idx < numOperands; idx++) {
4879	      auto operandTy = dyn_cast<TileType>(operands[idx].getType());
4880	      if (!operandTy)
4881	        return op->emitOpError()
4882	               << "expected TileType for operand at index " << idx
4883	               << " but got: " << operands[idx].getType();
4884	      auto identityTy = cast<TypedAttr>(identities[idx]).getType();
4885	      if ((operandTy.getElementType().isBF16() && identityTy.isF16()) ||
4886	          (operandTy.getElementType().isF16() && identityTy.isBF16()))
4887	        continue;
4888	      if (operandTy.getElementType() != identityTy) {
4889	        return op->emitOpError()
4890	               << "expect same type for operand at index: " << idx
4891	               << " and identity at index: " << idx
4892	               << " but got: " << operandTy.getElementType() << " and "
4893	               << identityTy;
4894	      }
4895	    }
4896	  }
4897	
4898	  // All the operand have the same shape see: SameOperandsShape.
4899	  auto firstOperandTy = dyn_cast<TileType>(operands[0].getType());
4900	  if (!firstOperandTy)
4901	    return op->emitOpError() << "expected TileType for first operand but got: "
4902	                             << operands[0].getType();
